        segment_ids, ov_opset.constant(0, segment_ids.get_element_type())
    ).output(0)
    safe_segment_ids = ov_opset.select(
        is_negative, num_segments, segment_ids
    ).output(0)
    indices = ov_opset.unsqueeze(
        safe_segment_ids, ov_opset.constant(-1, Type.i32)
    ).output(0)

